var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"벌써 계약기간이 끝났군요. 시간이 정말 순식간에 지나가네요.","JPN":"もう契約期間満了ですか。本当にあっという間ですね。","ENG":"I can't believe our contract is coming to an end. Time really does fly by.","TWN":"合約這麼快就到期啦，時間過得還真快呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스를 이용해 주셔서 감사했습니다. 모쪼록 도움이 되었길 바랍니다.","JPN":"フローラメイドサービスをご利用いただきありがとうございました。お役に立てたのなら幸いです。","ENG":"Thank you for using Flora Maid Service. We hope we served you well.","TWN":"謝謝您利用芙蘿拉女僕的服務，希望有幫上您的忙。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그럼요. 큰 도움이 됐죠. 매년 이 시기만 되면 뜬눈으로 밤을 새우는 게 일상이었는데.","JPN":"もちろんです。おおいに助かりました。毎年この時期になると一睡もできなかったのに。","ENG":"Absolutely! It's become a habit of mine to stay up all night during this time of year.","TWN":"那當然，幫我很大的忙呢。每年只要到這個時候，熬夜根本是家常便飯。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"베로니카 씨 한 명이 우리 비서 서너 명보다 낫다니까요. 솔직히 반신반의했거든요.","JPN":"ベロニカさんの方が、うちの会社の秘書三～四人合わせたより役に立つわ。正直半信半疑だったけれど。","ENG":"I was skeptical at first, but... Veronica, you're better than four of my secretaries combined!","TWN":"我3、4個祕書都比不上貝洛妮卡你一個人，其實我原本還有點半信半疑呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"과찬이십니다.","JPN":"褒めすぎです。","ENG":"I'm flattered.","TWN":"您過獎了。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네도 빨래하느라 무지 바빴지 말임다!","JPN":"モネも洗濯でめちゃくちゃ忙しかったっす！","ENG":"Mone was also busy doin' laundry, ma'am!","TWN":"莫妮也很努力洗衣服喔！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"모네도 고마웠어요. 유학 간 딸내미 같아서 참 보기 좋더라고요.","JPN":"モネもお疲れさまでした。留学中の娘を見ているようで本当に楽しかったわ。","ENG":"Thank you too, Mone. Having you around made me think about my daughter studying abroad right now.","TWN":"對，我也很謝謝莫妮，而且你和我去留學的女兒長得好像，看到你就開心。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메이드장님, 들으셨슴까! 모네 칭찬 받았슴다!","JPN":"メイド長、聞いたっすか！　モネ、褒めてもらたっす！","ENG":"Chief Maid! Did you hear! Mone got a compliment!","TWN":"女僕長，你有聽到嗎？莫妮被稱讚咧！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후후, 그래요. 모네도 이제 어엿한 메이드네요.","JPN":"ふふ、そうですね。モネももう立派なメイドです。","ENG":"Ha ha. That I did. Now you're a real maid, Mone.","TWN":"呵呵，對呀，你現在也是個扎扎實實的女僕囉。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그래서 말인데 우리 회사와 전속 계약을 맺는 건 어때요?","JPN":"それでなんですけれど、私の会社と専属契約をしてもらえないかしら？","ENG":"Speaking of... How would you like to make an exclusive contract with us?","TWN":"我是想問，你有意願和我們公司簽訂專屬契約嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"찾는 곳이 많겠지만, 안정적인 수입원이라고 생각하면 나쁘지 않은 제안 아닌가요?","JPN":"依頼は多いでしょうけど、安定的な収入源だと思えば悪くない提案だと思うわ。","ENG":"I know you must have a lot of clients, but having a steady stream of income surely mustn't sound bad?","TWN":"我知道一定很多人找你，但若你想要有穩定的收入來源，這應該是個不錯的提議吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송합니다. 이미 모시는 주인님이 계셔서 전속이라는 형식은 어려울 것 같군요.","JPN":"申し訳ありません。すでに主がおりますので、専属という形ではお受けできません。","ENG":"I'm sorry. But we already have a master we follow, so an exclusive contract would be difficult.","TWN":"很抱歉，我是有主人的，恐怕無法簽訂專屬契約。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그렇군요. 선수를 뺏긴 기분이라 조금 질투나네요.","JPN":"……そうですか。先手を打たれてしまったようで少し妬けますね。","ENG":"I see. I must admit I feel a bit envious. I wonder who the lucky person is...","TWN":"原來如此，有種人才被搶走的感覺，有點忌妒呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그 주인님이란 분도 베로니카 씨처럼 좋은 사람이겠죠?","JPN":"あなたの仕える主という方も、ベロニカさんのようにいい人なのでしょう。","ENG":"But I'm sure your master must be kindhearted and gentle like you, Veronica.","TWN":"我想那位主人，應該和貝洛妮卡一樣，是個很棒的人吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그렇슴다! 무지 재밌는 분이시지 말임다!","JPN":"そうっす！　めちゃくちゃ面白い方っすよ！","ENG":"Yup! He's really funny too, ma'am!","TWN":"沒錯唷！是位非常好玩的人唷！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……네. 저 같은 것과 비교하기 송구스러울 정도시죠.","JPN":"……はい。私のような者と比べるのが申し訳ないくらいです。","ENG":"...Yes. I would feel embarrassed if I were to be compared to someone so generous...","TWN":"……是的，不過拿我和他比，我有點自慚形穢呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그래도 내년 이맘때 계약은 미리 비워놔 주세요. 작년처럼 두 달 내내 철야 뛰긴 싫으니까.","JPN":"それでも、来年のこの時期の契約はあらかじめ空けておいてくださいね。去年のように二か月間ずっと徹夜はしたくないわ。","ENG":"However, please leave an opening for me next year around this time in advance. I'd hate to pull an all-nighter for two months straight like last year.","TWN":"那至少請你明年這個時候可以把時間空下來，我不想像去年一樣連續二個月無法睡覺。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"기억해 두겠습니다.","JPN":"覚えておきます。","ENG":"I will keep it in mind, sir.","TWN":"我會記得的。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 이건, 무척 실례되는 질문이 되겠습니다만……","JPN":"それからこれは、失礼を承知でお聞きするのですが……","ENG":"Oh and... This might be asking for too much, but...","TWN":"另外，這個問題非常失禮……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"대표님께서는 양친을 갑작스럽게 여의시는 바람에 대표직에 오르셨다고 들었습니다.","JPN":"代表はご両親を急に亡くされて、代表の職に就かれたとお聞きました。","ENG":"I heard that you became the CEO after the sudden loss of both of your parents.","TWN":"但我聽說您是因為雙親突然離世，才接下代表一職的。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"……그래요. 또 직원들이 어디서 수군거렸나 보군요.","JPN":"……そうです。また職員たちがどこかで噂話でもしていたようですね。","ENG":"...Yes. I see some of my employees have been talking again.","TWN":"……沒錯，看來又有員工在那說閒話是吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"미리 말해 두는데 부모님을 살해한 사람은 제가 아니에요.","JPN":"言っておきますが、両親を殺したのは私ではありませんよ。","ENG":"Just to be clear, I didn't kill my parents.","TWN":"我先把話說清楚，我不是殺害父母的兇手。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아뇨. 비난하려는 의도로 여쭤 보려는 것은 아니랍니다.","JPN":"いいえ。責める意図でお聞きしたわけではありません。","ENG":"No, that's not at all what I wanted to ask.","TWN":"請別誤會，我這麼問不是要指責您的意思。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"만약 양친을 살해한 자가 대표님께 용서를 빌겠다고 나타난다면……","JPN":"もしご両親を殺した者が代表に許しを請いたいと現れたら……","ENG":"If the killer were to appear in front of you asking for your forgiveness...","TWN":"我是想問，若是殺害您父母親的兇手，現在出現在您眼前祈求原諒……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"대표님께서는…… 어떻게 하실 건가요?","JPN":"代表は……どうなさいますか？","ENG":"What would... you do, ma'am?","TWN":"那您……會怎麼做呢？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"회사를 덜컥 물려받은 뒤로 부모 죽여 신세 폈다고 손가락질 받으면서 살았어요.","JPN":"降って湧いたような会社の相続があってからというもの、親を殺して運が開けたと後ろ指を指されてきました。","ENG":"I've been criticized for killing my parents and inheriting this company.","TWN":"我突然接掌公司後，大家都對我指指點點的，說我是殺死父母才上位的。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"이제 와서 그 자를 용서한다고 젊은 시절에 사무실에서 버린 시간들이 돌아오기라도 하나요?","JPN":"今更その者を許したとして、若い頃に執務室に費やした時間が戻ってくるわけでもないでしょう。","ENG":"But, even if I forgive the perpetrator, would that make up for all the time I wasted in the office over the years?","TWN":"現在就算我願意原諒，但我年輕時在辦公室遺失的時間還能回來嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"제가 회사를 경영하면서 배운 점은, 확실한 리턴 없이 결정을 내리면 안 된다는 거예요.","JPN":"私が会社を経営しながら学んだことは、確かなリターンなしで物事を決めてはいけないということです。","ENG":"If there's one thing I've learned from running a business, it's that decisions should not be made without tangible results.","TWN":"我在經營公司的過程中學到一件事，就是不做沒有實質回報的決定。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇겠죠…….","JPN":"そうでしょうね……","ENG":"I see...","TWN":"我想也是……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송합니다. 실례되는 질문으로 심기를 어지럽혔으니, 대금은 받지 않겠습니다.","JPN":"申し訳ございません。不躾な質問でご機嫌を損ねましたので、代金はいただきません。","ENG":"I apologize for asking such a rude question. In return, I won't accept any payment.","TWN":"很抱歉，問您這麼失禮的問題，勾起您不愉快的回憶，這次我願意不收費。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메이드장님, 아까부터 왜 그렇게 표정이 우거지상이심까?","JPN":"メイド長、さっきからなんでしかめっ面なんすか？","ENG":"Chief Maid, why are you looking so grim?","TWN":"女僕長，你怎麼從剛剛就一臉苦瓜臉咧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"기운 없을 때는 모네에게 말해 주십셔! 맛있는 물고기를 잡아 오겠슴다!","JPN":"元気がない時にはモネに話してくださいっす！　美味しい魚を釣ってくるっす！","ENG":"When you're feelin' down, leave it up to Mone! I'll catch you a tasty fish, ma'am!","TWN":"覺得無力時就跟莫妮說唄！莫妮去抓好吃的魚給你吃！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……대표님의 부모님을 살해한 사람은 저였어요.","JPN":"……代表のご両親を殺害したのは私なんです。","ENG":"...I'm the one who killed the CEO's parents.","TWN":"……殺害代表父母的人就是我。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"엑? 저, 정말임까?","JPN":"えっ？　ま、マジっすか？","ENG":"Eck? A-are you sure?","TWN":"啥？是…真的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 맨션에 있을 때 받은 지령이었죠.","JPN":"はい。マンションにいた時に受けた指令でした。","ENG":"Yes. It was an order when I was working for Mansion.","TWN":"是真的，是我在曼森時執行過的任務。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그럼 왜 말씀 안 하신 검까? 대표님도 착한 분이시니까 분명 용서해 주셨지 말임다!","JPN":"じゃあ、どうして話さなかったんすか？　代表はいい人だし、きっと許してくれたはずっす！","ENG":"Then why didn't you say anything? She looks like a nice guy. I'm sure she'll forgive you, ma'am!","TWN":"那你為什麼不告訴代表咧？代表人那麼好，他一定會原諒你的唄！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……맞아요, 모네.","JPN":"……そうですね、モネ。","ENG":"...You're right, Mone.","TWN":"……是沒錯，莫妮。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 희생된 분들의 가족 분들을 만나뵐수록…….","JPN":"ですが、犠牲になった方々のご家族とお会いするたびに……  ","ENG":"But the more I meet the families of the victims...","TWN":"但見到受害者的家屬後……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제가 그 분들께 용서를 강요하는 것 아닌지 두렵답니다.","JPN":"私があの方々に許しを押しつけているのではないかと怖いのです。","ENG":"I fear that I might be forcing them to forgive me.","TWN":"我擔心是不是我在強求他們的原諒。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"대표님 말씀처럼 용서를 받아서 편해지는 건 저뿐이에요.","JPN":"代表の言葉どおり、許されて楽になるのは私だけです。","ENG":"As she said, I'm the only one who will feel better by being forgiven.","TWN":"就如代表所言，得到原諒後，解脫的就只有我而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"법은 저 분들의 감정을 해소해 주진 않았어요. 많은 문제가 얽혀 있었으니까요.","JPN":"法は犠牲となった方々の感情を解消してはくれませんでした。多くの問題が絡まっていたからです。","ENG":"Even the law couldn't do anything for them because of all the issues that were involved with the case.","TWN":"法律無法使他們得到安慰，畢竟牽扯到很多問題。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"기부도, 봉사도, 가족을 잃은 분들의 눈에는 죄책감을 덜기 위한 행위로 보일지도 몰라요.","JPN":"寄付も、奉仕も、家族を失った人たちの目には罪悪感を軽くするための行為に見えるかもしれません。","ENG":"Perhaps all of my donating and volunteering will be seen as an attempt to alleviate my guilt in their eyes.","TWN":"無論我捐錢或是造橋鋪路，在受害者家屬看來，或許都只是想減輕罪惡感而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는……. 이렇게 계속 지내도 괜찮은 걸까요?","JPN":"私は……ずっとこのまま生きていってもいいのでしょうか。","ENG":"Do you... think it is okay for me to keep doing this?","TWN":"我……可以繼續這樣過下去嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우으……. 너무 어려운 질문임다…….","JPN":"うう……とても難しい質問っす……","ENG":"Err... That's a difficult question for me to answer...","TWN":"呃……這個問題好難唷……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그래도 모네는 알고 있지 말임다! 그건 전부 마귀 할멈이 못된 검다!","JPN":"でもモネは知ってるっす！　それは全部ババアが悪いんすよ！","ENG":"But there's one thing that I know, ma'am! That's that it's all the witch's fault!","TWN":"不過莫妮很清楚唷！那全都是魔鬼老太婆的錯！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그러니까 메이드장님이 계속 슬퍼하면 안 됨다!","JPN":"だからメイド長はくよくよしてちゃダメっす！","ENG":"So there's no need for you to be sad, Chief Maid!","TWN":"所以女僕長你不可以再一直難過下去唷！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래요. 그렇게 말해 줘서 고마워요, 모네.","JPN":"そうですね。そう言ってくれてありがとうございます、モネ。","ENG":"All right. Thank you for cheering me up, Mone.","TWN":"好，謝謝你的安慰，莫妮。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"회사에 다른 직원 분들이 주신 답례품을 놓고 왔네요. 숙소로 먼저 돌아가 보겠어요?","JPN":"会社に他の職員がくださったお返しを置いて来てしまいました。先に帰っていてください。","ENG":"Oh my, I forgot to bring the gifts at the company. Would you go back to the dorm first without me?","TWN":"我把其他員工送我的謝禮忘在公司了，你先回宿舍好嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네도 같이 가면 안 됨까?","JPN":"モネも一緒に行っちゃダメっすか？","ENG":"Can't Mone come with you?","TWN":"莫妮不能一起去嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"오늘은 리코리스가 식사 당번이랍니다.","JPN":"今日はリコリスが食事当番ですよ。","ENG":"I heard Lycoris is on kitchen duty today.","TWN":"聽說今天輪到莉克麗絲負責煮飯。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"얼른 가서 막아야겠슴다!","JPN":"早く行って止めないとダメっすね！","ENG":"Then I should head back quick, ma'am!","TWN":"那我要趕緊回去阻止她！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메이드장님도 늦지 마십셔! 늦게 오면 릴리 선배가 메이드장님이랑 같이 먹겠다고 쫄쫄 굶을 검다!","JPN":"メイド長も遅くならないでくださいっす！　遅くなるとリリー先輩がメイド長と一緒に食べるからって駄々こねるっすよ！","ENG":"Chief Maid! Don't take too long! If you do, Lily will be starving all day just so she can eat with you!","TWN":"女僕長也不要太晚回來唷！不然莉莉一定會餓著肚子說要等女僕長回來一起吃。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정하지 마세요. 오래 안 걸릴 거예요.","JPN":"心配しないでください。すぐ行きます。","ENG":"Don't worry, it won't take long.","TWN":"放心吧，我很快就回去。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"세 분 모두, 이제 그만 모습을 드러내시죠.","JPN":"三人とも、隠れていないで出てきてください。","ENG":"Now, will the three of you please show yourselves?","TWN":"現在，請你們三位現身吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"도회지와 가까운 만큼 소지하신 무기는 사용하지 않는 것을 추천드리겠습니다.","JPN":"繁華街が近いので、所持されている武器は使わないことをおすすめします。","ENG":"However, being close to the city, I recommend you don't use your weapons.","TWN":"畢竟是在城裡，我建議你們還是別使用身上的武器比較好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"들려, 대장? 미행이 들킨 것 같아.","JPN":"聞こえてる？　隊長。尾行がバレた。","ENG":"Did you hear that, Captain? I think she caught on to us.","TWN":"隊長？你有聽到嗎？我們形跡敗露了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에엥? 이 거리에서 셋 다? 우리가 역으로 저쪽 사람들에게 감시당한 거 아니에요?","JPN":"ええっ？　この距離で全員？　私たち、逆に監視されてたんですかね？","ENG":"Huh? She spotted all three of us all the way from there? Wasn't it us who were spying on her, and not the other way around?","TWN":"嘖嘖？我們三人都露餡兒？我們是不是反過來被監視啦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"무슨 수를 썼는지 모르겠군.","JPN":"どんな手を使ったのかわからないな。","ENG":"No idea how she did.","TWN":"她是怎麼發現的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 소문 이상인 건 확실해. 갑자기 외진 곳으로 온 것도 우릴 상대하기 위해서였나.","JPN":"だが、実力が噂以上なのは確かだ。いきなりへんぴなところに行くと思ったが、俺たちを相手するためだったのか。","ENG":"I guess the rumors about her were true and more. Did she walk all the way out here just to deal with us?","TWN":"不過可以確定的是，她的實力在傳言之上。突然來到這麼偏僻的地方，也是因為要對付我們吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……뭐가 됐든 상관없어, 대장.","JPN":"……なんだっていいよ、隊長。","ENG":"Whatever the case, it doesn't matter, Captain.","TWN":"……不管怎麼樣都無所謂啦，隊長。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"오래 끌고 싶지 않아. 저쪽이 원한다면……","JPN":"長引かせたくない。あちらが望むのなら……","ENG":"I don't want to drag this out any longer. If this is what she wants, then...","TWN":"我不想拖太久，若這是她想要的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"바라는 대로, 정면에서 상대해 주겠어.","JPN":"望みどおり、正面から相手してやる。","ENG":"I'll give her, and face her head on.","TWN":"那我就如她所願，正面迎戰！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"}]`);export{e as default};